query GetOrgSummaryViaCampaigns($first: Int) {
  campaignOrdersConnection(first: $first) {
    edges {
      node {
        id
        name
        advertiser {
          id
          name
          website
          level
          orgSummary {
            totalCampaigns
            activeCampaigns
            liveCampaigns
            impressions
            budget
            roas
            totalRevenue
            totalOrders
          }
        }
      }
    }
  }
}

query ListOrganizationsWithSummary($first: Int, $orderBy: OrgOrderByInput) {
  orgsConnection(first: $first, orderBy: $orderBy) {
    edges {
      node {
        id
        name
        website
        level
        createdAt
        orgSummary {
          totalCampaigns
          liveCampaigns
          activeCampaigns
          impressions
          roas
          totalRevenue
          budget
        }
      }
    }
    aggregate {
      count
    }
    pageInfo {
      hasNextPage
      endCursor
    }
  }
}
